const p = $input.first().json;
const riskLabel = p.risk_score >= 80 ? 'CRITICAL' : 'HIGH';
return [{
  json: {
    subject: `[COMPLIANCE] ${riskLabel} risk KYC profile — Score ${p.risk_score}/100 (User ${p.user_id})`,
    body: `A KYC profile has been automatically escalated due to elevated risk indicators.

User ID: ${p.user_id}
Profile ID: ${p.profile_id}
Risk score: ${p.risk_score}/100
PEP flag: ${p.pep_flag}
Sanctions flag: ${p.sanctions_flag}
Balance frozen: ${p.balance_frozen}
Trace ID: ${p.trace_id}

This profile requires senior compliance officer review before any approval.

Admin panel: ${process.env.ADMIN_BASE_URL}/admin/kyc/profiles/${p.profile_id}`
  }
}];
